      }
    ],
    "비결정사항": [
      {
        "항목": "README 설치 절차 검토",
        "내용": "목요일까지 가능하면 검토하자는 의견은 있었으나 담당자는 지정되지 않았다."
      },
      {
        "항목": "Hara의 tarball path 확인 시점",
        "내용": "Minjun의 스모크 결과 공유 이후 확인하기로 했으나 정확한 마감 시점은 정해지지 않았다."
      }
    ],
    "리스크": [
      {
        "항목": "tarball 경로 오류",
        "영향": "릴리스 지연 가능성"
      },
      {
        "항목": "README 설치 절차 최신성 부족",
        "영향": "릴리스 노트가 사용자에게 오해를 줄 가능성"
      }
    ],
    "오픈_질문": [
      {
        "질문": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "질문": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ]
  },
